func upsertHistory(db *gorm.DB, e *model.HistoryEvent) {
	db.Clauses(clause.OnConflict{
		Columns:   []clause.Column{{Name: "slug"}},
		DoUpdates: clause.AssignmentColumns([]string{"title", "description", "year_hijri", "year_miladi", "category", "is_significant"}),
	}).Create(e)
}

func seedHistoryEvents(db *gorm.DB) {
	events := []model.HistoryEvent{
		{YearHijri: -53, YearMiladi: 570, Title: "Kelahiran Nabi Muhammad ﷺ", Slug: "kelahiran-nabi", Description: "Nabi Muhammad ﷺ lahir di Makkah pada 12 Rabi'ul Awwal, Tahun Gajah (570 M). Ayahnya, Abdullah, wafat sebelum beliau lahir. Ibunya, Aminah binti Wahb, menyusui beliau hingga beberapa bulan, kemudian diserahkan kepada Halimah Sa'diyah dari Bani Sa'd untuk disusui di pedesaan.\n\nSumber: Ar-Raheeq Al-Makhtum, hal. 56-65", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: -43, YearMiladi: 580, Title: "Wafatnya Ibu Nabi: Aminah binti Wahb", Slug: "wafat-aminah", Description: "Ketika Nabi ﷺ berusia sekitar 6 tahun, ibunya Aminah wafat di Abwa' dalam perjalanan pulang dari Madinah (Yatsrib) setelah mengunjungi keluarga ayahnya. Beliau kemudian diasuh oleh kakeknya, Abdul Muthalib.\n\nSumber: Ar-Raheeq Al-Makhtum, hal. 67", Category: model.HistoryCategoryNabi, IsSignificant: false},
		{YearHijri: -40, YearMiladi: 583, Title: "Wafatnya Abdul Muthalib, Kakek Nabi", Slug: "wafat-abdul-muthalib", Description: "Ketika Nabi ﷺ berusia 8 tahun, kakeknya Abdul Muthalib wafat. Penjagaan beliau kemudian diserahkan kepada pamannya, Abu Thalib.\n\nSumber: Sirah Ibnu Hisyam", Category: model.HistoryCategoryNabi, IsSignificant: false},
		{YearHijri: -28, YearMiladi: 595, Title: "Pernikahan Nabi dengan Khadijah", Slug: "pernikahan-khadijah", Description: "Pada usia 25 tahun, Nabi ﷺ menikahi Khadijah binti Khuwailid (40 tahun) setelah beliau bekerja sebagai pedagang untuk Khadijah. Khadijah adalah wanita pertama yang masuk Islam dan merupakan istri paling dicintai Nabi. Mereka dikaruniai 6 anak: Qasim, Abdullah, Zainab, Ruqayyah, Ummu Kulsum, dan Fatimah.\n\nSumber: Ar-Raheeq Al-Makhtum, hal. 83", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 1, YearMiladi: 610, Title: "Turunnya Wahyu Pertama (Nuzulul Quran)", Slug: "wahyu-pertama", Description: "Pada malam 17 Ramadan, tahun 610 M, ketika Nabi ﷺ berusia 40 tahun sedang berkhalwat di Gua Hira, malaikat Jibril datang dan menurunkan wahyu pertama: QS. Al-Alaq ayat 1-5 ('Iqra' bismi rabbika...'). Inilah awal kenabian Muhammad ﷺ.\n\nSumber: HR. Bukhari No. 3, Muslim No. 160", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 3, YearMiladi: 613, Title: "Dakwah Terbuka di Makkah", Slug: "dakwah-terbuka-makkah", Description: "Setelah 3 tahun dakwah secara sembunyi-sembunyi (sirriyah), Nabi ﷺ diperintahkan untuk berdakwah secara terang-terangan berdasarkan QS. Al-Hijr: 94. Beliau menyeru keluarga besar Bani Hasyim di bukit Shafa: 'Andaikan kuberitahu kalian bahwa di balik bukit ini ada pasukan kuda yang hendak menyerang kalian, apakah kalian percaya?' Mereka menjawab: 'Ya.' Beliau berkata: 'Sesungguhnya aku adalah pemberi peringatan kepada kalian dari azab yang pedih.'\n\nSumber: HR. Bukhari No. 4770, Muslim No. 208", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 5, YearMiladi: 615, Title: "Hijrah Pertama ke Habasyah", Slug: "hijrah-habasyah", Description: "Karena tekanan keras kaum Quraisy, Nabi ﷺ mengizinkan sekelompok kaum muslimin (sekitar 15 orang, dipimpin Utsman bin Affan) untuk berhijrah ke Habasyah (Ethiopia) mencari perlindungan kepada Raja Najasyi (Ashhamah). Ini adalah hijrah pertama dalam sejarah Islam.\n\nSumber: Ar-Raheeq Al-Makhtum, hal. 128", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 10, YearMiladi: 619, Title: "Tahun Duka Cita ('Aam Al-Huzn)", Slug: "tahun-duka-cita", Description: "Dalam satu tahun yang sama, dua orang paling dekat dengan Nabi ﷺ wafat: pertama, Khadijah istri beliau yang setia selama 25 tahun; kemudian Abu Thalib paman yang selalu melindungi beliau meski tidak masuk Islam. Nabi ﷺ sangat berduka, dan tahun ini dikenal sebagai 'Aam Al-Huzn' (Tahun Duka Cita).\n\nSumber: Ar-Raheeq Al-Makhtum, hal. 163", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 10, YearMiladi: 621, Title: "Isra' Mi'raj", Slug: "isra-miraj", Description: "Nabi ﷺ diperjalankan dari Masjidil Haram ke Masjidil Aqsha (Isra'), kemudian naik ke Sidratul Muntaha (Mi'raj) dalam satu malam. Di sinilah beliau menerima perintah sholat 5 waktu langsung dari Allah SWT — awalnya 50 waktu, kemudian dikurangi menjadi 5 waktu atas saran Nabi Musa as.\n\nSumber: HR. Bukhari No. 349, Muslim No. 163; QS. Al-Isra: 1", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 13, YearMiladi: 622, Title: "Hijrah ke Madinah", Slug: "hijrah-madinah", Description: "Pada bulan Rabi'ul Awwal tahun 622 M, Nabi ﷺ dan Abu Bakar berhijrah dari Makkah ke Madinah (Yatsrib). Peristiwa ini menjadi tonggak awal kalender Hijriah dan pembentukan komunitas Islam pertama. Di Madinah, Nabi ﷺ mempersaudarakan kaum Muhajirin dan Anshar, serta menyusun Piagam Madinah.\n\nSumber: Ar-Raheeq Al-Makhtum, hal. 201-215", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 2, YearMiladi: 624, Title: "Perang Badar", Slug: "perang-badar", Description: "Perang Badar (17 Ramadan 2 H / 624 M) adalah perang besar pertama kaum muslimin. 313 pasukan Muslim menghadapi 1.000 pasukan Quraisy. Dengan pertolongan Allah, kaum muslimin menang. 70 musuh tewas (termasuk pemimpin Quraisy: Abu Jahal) dan 70 tertawan. Kemenangan ini memperkuat posisi Islam di jazirah Arab.\n\nSumber: HR. Bukhari No. 3992; QS. Al-Anfal: 9", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 3, YearMiladi: 625, Title: "Perang Uhud", Slug: "perang-uhud", Description: "Dalam perang Uhud (7 Syawal 3 H), kaum muslimin awalnya unggul namun sebagian pasukan pemanah meninggalkan posnya karena rakus terhadap harta rampasan. Hal ini dimanfaatkan Khalid bin Walid (saat itu masih kafir) untuk menyerang dari belakang. 70 sahabat syahid termasuk Hamzah bin Abdul Muthalib. Nabi ﷺ sendiri terluka.\n\nSumber: HR. Bukhari No. 4043; QS. Ali Imran: 121-179", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 5, YearMiladi: 627, Title: "Perang Khandaq (Ahzab)", Slug: "perang-khandaq", Description: "Kaum Quraisy bersama sekutu (sekitar 10.000 pasukan) mengepung Madinah. Atas saran Salman Al-Farisi, Nabi ﷺ memerintahkan penggalian parit (khandaq) di utara Madinah. Pengepungan berlangsung sebulan tanpa berhasil menerobos. Akhirnya Allah mengutus angin kencang yang memorak-porandakan pasukan musuh dan mereka mundur.\n\nSumber: HR. Bukhari No. 4106; QS. Al-Ahzab: 9-27", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 6, YearMiladi: 628, Title: "Perjanjian Hudaibiyyah", Slug: "perjanjian-hudaibiyyah", Description: "Nabi ﷺ dan 1.400 sahabat berangkat untuk umrah, namun dihadang Quraisy di Hudaibiyyah. Ditandatangani perjanjian damai 10 tahun: kaum muslimin tidak boleh umrah tahun ini, namun boleh tahun depan; jika ada Quraisy yang lari ke Muslim harus dikembalikan, tapi jika ada Muslim yang lari ke Quraisy tidak perlu dikembalikan. Meski tampak merugikan, Allah menyebutnya sebagai 'kemenangan yang nyata' (QS. Al-Fath: 1).\n\nSumber: HR. Bukhari No. 2731; QS. Al-Fath: 1-3", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 8, YearMiladi: 630, Title: "Fathu Makkah (Pembebasan Makkah)", Slug: "fathu-makkah", Description: "Setelah Quraisy melanggar perjanjian Hudaibiyyah, Nabi ﷺ bergerak dengan 10.000 pasukan menuju Makkah. Kota Makkah menyerah hampir tanpa perlawanan pada 20 Ramadan 8 H. Nabi ﷺ memberi amnesti umum kepada penduduk Makkah: 'Pergilah kalian, kalian bebas.' Ka'bah dibersihkan dari 360 berhala. Mayoritas penduduk Makkah masuk Islam.\n\nSumber: HR. Bukhari No. 4280; Ar-Raheeq Al-Makhtum, hal. 376-386", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 10, YearMiladi: 632, Title: "Haji Wada' dan Khutbah Terakhir", Slug: "haji-wada", Description: "Pada tahun 10 H (632 M), Nabi ﷺ melaksanakan haji terakhir bersama lebih dari 100.000 sahabat. Di Padang Arafah, beliau menyampaikan Khutbah Wada' yang berisi prinsip-prinsip fundamental Islam: kesetaraan manusia, kesucian darah dan harta, penghapusan riba, hak-hak perempuan, dan amanah Al-Quran & Sunnah. Turun QS. Al-Maidah: 3 menyatakan kesempurnaan agama Islam.\n\nSumber: HR. Bukhari No. 1741, Muslim No. 1218", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 11, YearMiladi: 632, Title: "Wafatnya Rasulullah ﷺ", Slug: "wafat-rasulullah", Description: "Pada Senin, 12 Rabi'ul Awwal 11 H (8 Juni 632 M), Nabi ﷺ wafat di kamar Aisyah ra. dalam usia 63 tahun. Abu Bakar berkhutbah: 'Barangsiapa menyembah Muhammad, sesungguhnya Muhammad telah wafat. Barangsiapa menyembah Allah, sesungguhnya Allah Maha Hidup tidak akan mati.' (QS. Ali Imran: 144). Beliau dikebumikan di tempat beliau wafat.\n\nSumber: HR. Bukhari No. 4448; Ar-Raheeq Al-Makhtum", Category: model.HistoryCategoryNabi, IsSignificant: true},
		{YearHijri: 11, YearMiladi: 632, Title: "Khalifah Abu Bakar Ash-Shiddiq (11-13 H)", Slug: "khilafah-abu-bakar", Description: "Abu Bakar ra. terpilih sebagai khalifah pertama melalui musyawarah di Saqifah Bani Sa'idah. Masa kekhalifahannya (632-634 M) ditandai dengan: (1) Memerangi kaum murtad (Riddah Wars), (2) Memerangi Musailamah Al-Kadzab, (3) Pengumpulan Al-Quran pertama kali atas usulan Umar bin Khattab dan dilaksanakan oleh Zaid bin Tsabit setelah banyak hafizh syahid di Yamamah.\n\nSumber: HR. Bukhari No. 4986", Category: model.HistoryCategoryKhulafa, IsSignificant: true},
		{YearHijri: 13, YearMiladi: 634, Title: "Khalifah Umar bin Khattab (13-23 H)", Slug: "khilafah-umar", Description: "Umar bin Khattab ra. menjadi khalifah kedua (634-644 M), ditunjuk langsung oleh Abu Bakar. Masa kekhalifahannya adalah masa ekspansi terbesar Islam: penaklukan Persia, Syam, dan Mesir. Beliau mendirikan sistem administrasi, menetapkan kalender Hijriah, membangun Baitul Mal, dan dikenal sebagai pemimpin yang sangat adil dan sederhana. Beliau syahid ditikam oleh Abu Lu'lu'ah Al-Majusi.\n\nSumber: Ar-Raheeq Al-Makhtum; Tarikh Ath-Thabari", Category: model.HistoryCategoryKhulafa, IsSignificant: true},
		{YearHijri: 23, YearMiladi: 644, Title: "Khalifah Utsman bin Affan (23-35 H)", Slug: "khilafah-utsman", Description: "Utsman bin Affan ra. terpilih melalui syura (musyawarah enam orang). Masa kekhalifahannya (644-656 M) ditandai dengan: (1) Pembukuan resmi Al-Quran (Mushaf Utsmani) yang menjadi standar hingga kini, (2) Ekspansi ke Afrika Utara dan Persia timur, (3) Pembangunan angkatan laut Islam pertama. Beliau syahid dibunuh oleh kaum pemberontak pada usia sekitar 82 tahun.\n\nSumber: HR. Bukhari No. 4986", Category: model.HistoryCategoryKhulafa, IsSignificant: true},
		{YearHijri: 35, YearMiladi: 656, Title: "Khalifah Ali bin Abi Thalib (35-40 H)", Slug: "khilafah-ali", Description: "Ali bin Abi Thalib ra. menjadi khalifah keempat (656-661 M). Masa kekhalifahannya diwarnai fitnah (ujian besar): Perang Jamal (melawan Aisyah, Thalhah, dan Zubair) dan Perang Shiffin (melawan Mu'awiyah). Kedua perang ini berakhir tanpa pemenang jelas. Ali ra. syahid ditikam Abdurrahman bin Muljam dari kelompok Khawarij. Kekhalifahannya menandai berakhirnya era Khulafaur Rasyidin.\n\nSumber: Tarikh Al-Khulafa, As-Suyuthi", Category: model.HistoryCategoryKhulafa, IsSignificant: true},
		{YearHijri: 41, YearMiladi: 661, Title: "Dinasti Umayyah (41-132 H / 661-750 M)", Slug: "dinasti-umayyah", Description: "Dinasti Umayyah didirikan oleh Mu'awiyah bin Abi Sufyan setelah Hassan bin Ali menyerahkan kekuasaan demi persatuan umat. Ibu kota dipindah ke Damaskus. Masa ini ditandai dengan ekspansi Islam terluas: ke Spanyol (Al-Andalus) di barat, Asia Tengah di timur, dan India. Puncak kejayaan pada masa Umar bin Abdul Aziz (Umar II, 99-101 H) yang terkenal dengan keadilannya.\n\nSumber: Tarikh Ath-Thabari; Al-Bidayah wan Nihayah", Category: model.HistoryCategoryDinasti, IsSignificant: true},
		{YearHijri: 132, YearMiladi: 750, Title: "Dinasti Abbasiyyah (132-656 H / 750-1258 M)", Slug: "dinasti-abbasiyyah", Description: "Dinasti Abbasiyyah menggantikan Umayyah dengan ibu kota Baghdad. Masa ini adalah Zaman Keemasan Islam (The Golden Age of Islam): kemajuan pesat ilmu pengetahuan, filsafat, matematika, astronomi, kedokteran (Ibnu Sina, Al-Khawarizmi, Al-Biruni, dll). Bayt Al-Hikmah (Rumah Kebijaksanaan) di Baghdad menjadi pusat keilmuan dunia. Berakhir dengan penghancuran Baghdad oleh Mongol (Hulagu Khan) pada 656 H/1258 M.\n\nSumber: Tarikh Al-Islam, Adz-Dzahabi", Category: model.HistoryCategoryDinasti, IsSignificant: true},
		{YearHijri: 656, YearMiladi: 1258, Title: "Jatuhnya Baghdad ke Tangan Mongol", Slug: "jatuhnya-baghdad", Description: "Pada 656 H (1258 M), pasukan Mongol di bawah Hulagu Khan menghancurkan Baghdad — ibu kota Kekhalifahan Abbasiyyah. Khalifah Al-Mu'tashim billah dibunuh. Jutaan manuskrip ilmu pengetahuan dibuang ke Sungai Tigris hingga air sungai berubah warna karena tinta. Peristiwa ini menandai berakhirnya kekuasaan Abbasiyyah di Baghdad.\n\nSumber: Al-Bidayah wan Nihayah, Ibnu Katsir", Category: model.HistoryCategoryPeristiwa, IsSignificant: true},
		{YearHijri: 583, YearMiladi: 1187, Title: "Shalahuddin Al-Ayyubi Membebaskan Yerusalem", Slug: "pembebasan-yerusalem", Description: "Setelah Yerusalem (Al-Quds) dikuasai Tentara Salib selama 88 tahun (1099-1187 M), Shalahuddin Al-Ayyubi (Saladin) berhasil membebaskannya pada 27 Rajab 583 H. Berbeda dengan penaklukan Tentara Salib yang penuh pembantaian, Shalahuddin memberikan amnesti kepada penduduk Kristen yang ingin pergi, dan melindungi gereja-gereja mereka.\n\nSumber: Al-Kamil fit Tarikh, Ibnu Al-Atsir", Category: model.HistoryCategoryPeristiwa, IsSignificant: true},
		{YearHijri: 926, YearMiladi: 1520, Title: "Puncak Kejayaan Kesultanan Utsmaniyah (Ottoman)", Slug: "ottoman-suleiman", Description: "Masa pemerintahan Sultan Suleiman Al-Qanuni (926-974 H / 1520-1566 M) merupakan puncak kejayaan Kesultanan Utsmaniyah. Wilayahnya mencakup tiga benua: Asia, Afrika, dan Eropa. Istanbul menjadi pusat peradaban Islam. Masjid Sulaiman (Süleymaniye Mosque) dibangun sebagai simbol kejayaan. Beliau juga dikenal sebagai legislator ulung.\n\nSumber: The Ottoman Empire and the World Around It, Suraiya Faroqhi", Category: model.HistoryCategoryDinasti, IsSignificant: true},
		{YearHijri: 150, YearMiladi: 767, Title: "Imam Abu Hanifah (80-150 H)", Slug: "imam-abu-hanifah", Description: "Nu'man bin Tsabit, dikenal sebagai Imam Abu Hanifah atau 'Al-Imam Al-A'zham' (Imam Terbesar). Pendiri mazhab Hanafi — mazhab fiqh terbesar di dunia (mencakup Turki, Asia Selatan, Asia Tengah). Dikenal dengan metode qiyas (analogi) yang kuat. Pernah dipenjara karena menolak jabatan qadhi (hakim) yang ditawarkan khalifah Abbasiyyah.\n\nSumber: Siyar A'lam An-Nubala, Adz-Dzahabi", Category: model.HistoryCategoryUlama, IsSignificant: true},
		{YearHijri: 179, YearMiladi: 795, Title: "Imam Malik bin Anas (93-179 H)", Slug: "imam-malik", Description: "Imam Malik bin Anas, pendiri mazhab Maliki. Karya monumentalnya Al-Muwaththa' adalah koleksi hadith tertua yang masih ada. Imam Syafi'i menyebutnya: 'Jika ulama disebut, maka Malik adalah bintang.' Pernah dihukum cambuk karena memberikan fatwa yang tidak sesuai keinginan penguasa. Muridnya tersebar di Afrika Utara dan Spanyol.\n\nSumber: Siyar A'lam An-Nubala, Adz-Dzahabi", Category: model.HistoryCategoryUlama, IsSignificant: true},
		{YearHijri: 204, YearMiladi: 820, Title: "Imam Muhammad bin Idris Asy-Syafi'i (150-204 H)", Slug: "imam-syafii", Description: "Imam Syafi'i adalah pendiri mazhab Syafi'i dan Ilmu Ushul Fiqh. Karya terbesarnya: Ar-Risalah (pertama membahas metodologi hukum Islam) dan Al-Umm. Beliau belajar kepada Imam Malik di Madinah dan murid-murid Abu Hanifah di Irak. Mazhab Syafi'i menjadi mazhab dominan di Indonesia, Malaysia, Mesir, dan sebagian besar dunia Muslim.\n\nSumber: Manaqib Asy-Syafi'i, Al-Baihaqi", Category: model.HistoryCategoryUlama, IsSignificant: true},
		{YearHijri: 241, YearMiladi: 855, Title: "Imam Ahmad bin Hanbal (164-241 H)", Slug: "imam-ahmad-hanbal", Description: "Imam Ahmad bin Hanbal, pendiri mazhab Hanbali dan Imam Ahli Sunnah. Karya terbesarnya: Musnad Ahmad (sekitar 30.000 hadith). Beliau mengalami ujian berat (Mihnah) di bawah Khalifah Al-Ma'mun dan Al-Mu'tashim yang memaksanya menerima paham Mu'tazilah bahwa Al-Quran adalah makhluk. Beliau menolak meski disiksa, dan menjadi simbol keteguhan aqidah.\n\nSumber: Manaqib Al-Imam Ahmad, Ibnu Al-Jauzi", Category: model.HistoryCategoryUlama, IsSignificant: true},
		{YearHijri: 256, YearMiladi: 870, Title: "Imam Al-Bukhari Menyelesaikan Shahih Bukhari (194-256 H)", Slug: "shahih-bukhari", Description: "Muhammad bin Ismail Al-Bukhari menyelesaikan kitab Shahih-nya — koleksi hadith paling shahih setelah Al-Quran. Dari 600.000 hadith yang dihafal, beliau memilih sekitar 7.275 hadith (2.602 tanpa pengulangan) setelah seleksi ketat selama 16 tahun. Imam Syafi'i berkata: 'Aku tidak melihat orang yang lebih faqih tentang hadith daripada pemuda dari Khurasan ini.'\n\nSumber: Hady As-Sari, Ibnu Hajar", Category: model.HistoryCategoryUlama, IsSignificant: true},
		{YearHijri: 728, YearMiladi: 1328, Title: "Ibnu Taimiyah (661-728 H)", Slug: "ibnu-taimiyah", Description: "Taqiyuddin Ahmad Ibnu Taimiyah — ulama besar mazhab Hanbali yang sangat berpengaruh. Hidup di masa invasi Mongol dan Tentara Salib, beliau aktif berjihad dan berfatwa. Dikenal dengan seruan kembali kepada Al-Quran dan Sunnah, menolak bid'ah dan khurafat. Dipenjara beberapa kali karena fatwa-fatwanya yang kontroversial. Muridnya: Ibnu Qayyim Al-Jauziyyah.\n\nSumber: Siyar A'lam An-Nubala, Adz-Dzahabi", Category: model.HistoryCategoryUlama, IsSignificant: true},
	}

	for i := range events {
		upsertHistory(db, &events[i])
	}
}

func seedManasikSteps(db *gorm.DB) {
	umrahSteps := []model.ManasikStep{
		{Type: model.ManasikTypeUmrah, StepOrder: 1, Title: "Miqat dan Niat Ihram", Description: "Miqat adalah batas tempat wajib memulai ihram. Untuk jemaah Indonesia umumnya miqat di Yalamlam (jalur laut) atau Bir Ali/Dzul Hulaifah (jalur Madinah-Makkah). Di miqat: mandi sunnah, memakai pakaian ihram (2 kain putih untuk laki-laki, baju biasa menutup aurat untuk perempuan), sholat sunnah ihram 2 rakaat, kemudian niat umrah.", Arabic: "لَبَّيْكَ اللَّهُمَّ عُمْرَةً", Transliteration: "Labbaika Allahumma 'umratan", TranslationText: "Aku memenuhi panggilan-Mu ya Allah untuk umrah.", Notes: "Larangan ihram: mencukur rambut/kuku, memakai wewangian, berhubungan suami-istri, berburu binatang, menikah/menikahkan.", IsWajib: true},
		{Type: model.ManasikTypeUmrah, StepOrder: 2, Title: "Talbiyah dalam Perjalanan", Description: "Setelah niat ihram, perbanyak membaca talbiyah dalam perjalanan menuju Makkah, terutama saat naik kendaraan, naik turun bukit, berpapasan dengan rombongan lain, dan di waktu-waktu utama.", Arabic: "لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ، لَبَّيْكَ لاَ شَرِيكَ لَكَ لَبَّيْكَ، إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ، لاَ شَرِيكَ لَكَ", Transliteration: "Labbaika Allahumma labbaik, labbaika laa syariika laka labbaik, innal hamda wan ni'mata laka wal mulk, laa syariika lak", TranslationText: "Aku memenuhi panggilan-Mu ya Allah, aku memenuhi panggilan-Mu. Aku memenuhi panggilan-Mu, tiada sekutu bagi-Mu, aku memenuhi panggilan-Mu. Sesungguhnya segala puji, nikmat, dan kerajaan adalah milik-Mu. Tiada sekutu bagi-Mu.", Notes: "Baca talbiyah dengan suara keras untuk laki-laki, pelan untuk perempuan.", IsWajib: false},
		{Type: model.ManasikTypeUmrah, StepOrder: 3, Title: "Memasuki Masjidil Haram", Description: "Masuk Masjidil Haram dengan kaki kanan terlebih dahulu, membaca doa masuk masjid dan doa melihat Ka'bah. Saat pertama kali melihat Ka'bah, panjatkan doa karena ini adalah waktu mustajab.", Arabic: "اللَّهُمَّ أَنْتَ السَّلاَمُ وَمِنْكَ السَّلاَمُ، فَحَيِّنَا رَبَّنَا بِالسَّلاَمِ", Transliteration: "Allahumma antas salaam wa minkas salaam, fa hayyina rabbana bis salaam", TranslationText: "Ya Allah, Engkau adalah Maha Sejahtera dan dari-Mu lah kesejahteraan, maka hidupkanlah kami wahai Tuhan kami dengan kesejahteraan.", Notes: "Saat melihat Ka'bah pertama kali: angkat tangan, berdoa, dan sampaikan hajat karena waktu mustajab.", IsWajib: false},
		{Type: model.ManasikTypeUmrah, StepOrder: 4, Title: "Thawaf (7 Putaran)", Description: "Thawaf adalah mengelilingi Ka'bah sebanyak 7 putaran berlawanan arah jarum jam, dimulai dan diakhiri di Hajar Aswad. Posisi Ka'bah selalu di sebelah kiri. Pada 3 putaran pertama, laki-laki dianjurkan berlari-lari kecil (raml). Baca doa dan dzikir selama thawaf sesuai sunnah.", Arabic: "بِسْمِ اللَّهِ وَاللَّهُ أَكْبَرُ", Transliteration: "Bismillahi wallahu Akbar", TranslationText: "Dengan menyebut nama Allah, dan Allah Maha Besar.", Notes: "Syarat thawaf: suci dari hadats, menutup aurat, Ka'bah di sebelah kiri. Tidak ada doa khusus per putaran — baca doa bebas, Al-Quran, atau dzikir.", IsWajib: true},
		{Type: model.ManasikTypeUmrah, StepOrder: 5, Title: "Sholat 2 Rakaat di Belakang Maqam Ibrahim", Description: "Setelah thawaf, sholat 2 rakaat di belakang Maqam Ibrahim (jika tidak memungkinkan karena penuh, boleh di tempat lain dalam Masjidil Haram). Rakaat pertama baca Al-Fatihah + Al-Kafirun, rakaat kedua baca Al-Fatihah + Al-Ikhlas.", Arabic: "وَاتَّخِذُوا مِن مَّقَامِ إِبْرَاهِيمَ مُصَلًّى", Transliteration: "Wattakhidzu min maqaami ibraahiima mushalla", TranslationText: "Dan jadikanlah sebagian maqam Ibrahim sebagai tempat sholat.", Notes: "Maqam Ibrahim adalah batu tempat Nabi Ibrahim berdiri saat membangun Ka'bah. QS. Al-Baqarah: 125.", IsWajib: true},
		{Type: model.ManasikTypeUmrah, StepOrder: 6, Title: "Sa'i (7 Kali antara Shafa dan Marwah)", Description: "Sa'i adalah berjalan 7 kali antara bukit Shafa dan Marwah — mengenang perjuangan Hajar mencari air untuk bayinya Ismail. Dimulai dari Shafa (hitungan 1) ke Marwah (hitungan 2), berakhir di Marwah (hitungan 7). Di Shafa dan Marwah, berhenti sejenak menghadap Ka'bah dan berdoa.", Arabic: "إِنَّ الصَّفَا وَالْمَرْوَةَ مِن شَعَائِرِ اللَّهِ", Transliteration: "Innas shofa wal marwata min sya'aa'irillah", TranslationText: "Sesungguhnya Shafa dan Marwah adalah sebagian dari syiar-syiar Allah.", Notes: "Berlari-lari kecil (bagi laki-laki) antara dua tanda hijau yang ada di lorong sa'i.", IsWajib: true},
		{Type: model.ManasikTypeUmrah, StepOrder: 7, Title: "Tahallul: Memotong Rambut", Description: "Tahallul adalah pencabutan larangan ihram dengan memotong rambut. Untuk laki-laki: dianjurkan mencukur habis (halq) atau minimal memotong sebagian rambut (taqshir, minimal 3 helai dari seluruh kepala). Untuk perempuan: memotong ujung rambut sepanjang ruas jari. Dengan tahallul, seluruh larangan ihram berakhir.", Arabic: "مُحَلِّقِينَ رُءُوسَكُمْ وَمُقَصِّرِينَ", Transliteration: "Muhalliqiina ru'usakum wa muqashshiriin", TranslationText: "Dengan mencukur kepala kalian dan memotong rambut.", Notes: "QS. Al-Fath: 27. Umrah selesai setelah tahallul.", IsWajib: true},
	}

	hajiSteps := []model.ManasikStep{
		{Type: model.ManasikTypeHaji, StepOrder: 1, Title: "Ihram dari Miqat (8 Dzulhijjah)", Description: "Pada 8 Dzulhijjah (Hari Tarwiyah), jemaah haji berihram dari miqat atau dari Makkah (bagi yang sudah di sana). Niat haji, kenakan pakaian ihram, baca talbiyah.", Arabic: "لَبَّيْكَ اللَّهُمَّ حَجًّا", Transliteration: "Labbaika Allahumma hajjan", TranslationText: "Aku memenuhi panggilan-Mu ya Allah untuk haji.", Notes: "Untuk haji tamattu': berihram khusus haji setelah tahallul dari umrah.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 2, Title: "Mabit di Mina (8 Dzulhijjah)", Description: "Pada 8 Dzulhijjah, jemaah berangkat ke Mina dan mabit (menginap) di sana. Ini adalah sunnah Nabi ﷺ. Di Mina, sholat Dzuhur, Ashar, Maghrib, Isya, dan Subuh diqashar (diringkas) tanpa dijama'.", Arabic: "", Transliteration: "", TranslationText: "", Notes: "Mabit di Mina 8 Dzulhijjah adalah sunnah. Yang wajib adalah mabit di Mina pada malam-malam 11-13 Dzulhijjah.", IsWajib: false},
		{Type: model.ManasikTypeHaji, StepOrder: 3, Title: "Wukuf di Arafah (9 Dzulhijjah) — Rukun Terpenting", Description: "Wukuf di Arafah pada 9 Dzulhijjah adalah rukun haji terpenting: 'Al-Hajj 'Arafah' (HR. Abu Dawud). Dimulai setelah tergelincir matahari (Dzuhur) hingga terbit fajar 10 Dzulhijjah. Perbanyak doa, dzikir, istighfar, membaca talbiyah. Di Arafah, sholat Dzuhur dan Ashar dijama'-qashar.", Arabic: "لاَ إِلَهَ إِلاَّ اللهُ وَحْدَهُ لاَ شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ، وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ", Transliteration: "Laa ilaaha illallah wahdahu laa syariika lah, lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai'in qadiir", TranslationText: "Tiada tuhan selain Allah, Maha Esa, tiada sekutu bagi-Nya. Milik-Nya kerajaan dan milik-Nya segala pujian, dan Dia Maha Kuasa atas segala sesuatu.", Notes: "Doa terbaik di Arafah adalah doa ini (HR. Tirmidzi No. 3585). Wukuf tidak sah jika tidak hadir di Arafah sama sekali.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 4, Title: "Mabit di Muzdalifah (Malam 10 Dzulhijjah)", Description: "Setelah matahari terbenam di Arafah, berangkat ke Muzdalifah. Di Muzdalifah: sholat Maghrib dan Isya dijama' (Maghrib 3 rakaat + Isya 2 rakaat), mabit hingga setelah sholat Subuh. Kumpulkan batu kerikil untuk jumrah (minimal 49 butir untuk 3 hari, atau 70 butir untuk 4 hari).", Arabic: "", Transliteration: "", TranslationText: "", Notes: "Wajib mabit di Muzdalifah. Yang udzur (sakit, wanita, lansia) boleh meninggalkan Muzdalifah setelah tengah malam.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 5, Title: "Melontar Jumrah Aqabah (10 Dzulhijjah)", Description: "Pada 10 Dzulhijjah (Hari Nahr/Idul Adha), setelah tiba di Mina, lempar Jumrah Aqabah (Jumrah Kubra) dengan 7 batu kerikil. Setiap lemparan diiringi takbir 'Allahu Akbar'. Setelah melontar, baca: 'Allahumma ij'alhu hajjan mabruran wa dzanban maghfuran'.", Arabic: "اللَّهُ أَكْبَرُ", Transliteration: "Allahu Akbar", TranslationText: "Allah Maha Besar", Notes: "Jumrah Aqabah adalah yang paling dekat ke Makkah. Waktu utama: setelah matahari terbit. HR. Bukhari No. 1751.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 6, Title: "Menyembelih Hewan Qurban (Haji Tamattu'/Qiran)", Description: "Bagi yang haji tamattu' atau qiran, wajib membayar dam (menyembelih hewan: kambing, atau 1/7 sapi/unta). Penyembelihan di Mina pada 10-13 Dzulhijjah.", Arabic: "", Transliteration: "", TranslationText: "", Notes: "Haji ifrad tidak wajib dam. Jika tidak mampu menyembelih, wajib puasa 3 hari selama haji dan 7 hari setelah pulang (total 10 hari). QS. Al-Baqarah: 196.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 7, Title: "Tahallul Awal: Mencukur/Memotong Rambut", Description: "Setelah melontar Jumrah Aqabah dan menyembelih (atau niat dam), lakukan tahallul awal dengan mencukur/memotong rambut. Dengan tahallul awal, sebagian larangan ihram berakhir: boleh memakai pakaian biasa, memotong kuku, memakai wewangian — kecuali berhubungan suami-istri.", Arabic: "", Transliteration: "", TranslationText: "", Notes: "Urutan sunnah di 10 Dzulhijjah: lontar jumrah → sembelih → cukur → thawaf ifadhah.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 8, Title: "Thawaf Ifadhah (Thawaf Ziarah) — Rukun Haji", Description: "Thawaf Ifadhah adalah rukun haji yang wajib dilakukan. Waktunya: setelah 10 Dzulhijjah. Tata caranya sama dengan thawaf umrah: 7 putaran mengelilingi Ka'bah. Setelah thawaf, sholat 2 rakaat di Maqam Ibrahim dan sa'i (jika belum sa'i sebelumnya).", Arabic: "وَلْيَطَّوَّفُوا بِالْبَيْتِ الْعَتِيقِ", Transliteration: "Walyatthowwafuu bil baytil 'atiiq", TranslationText: "Dan hendaklah mereka melakukan thawaf sekeliling rumah yang tua itu.", Notes: "QS. Al-Hajj: 29. Tahallul tsani (lengkap) terjadi setelah thawaf ifadhah: semua larangan ihram berakhir.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 9, Title: "Mabit di Mina dan Lontar 3 Jumrah (11-12/13 Dzulhijjah)", Description: "Kembali ke Mina, mabit pada malam 11 dan 12 Dzulhijjah (wajib). Pada siang 11 dan 12 Dzulhijjah (setelah zawal/tergelincir matahari), lempar 3 jumrah: Jumrah Ula (7 batu), Jumrah Wustha (7 batu), Jumrah Aqabah (7 batu). Boleh nafar awwal (pulang 12 Dzulhijjah sebelum Maghrib) atau nafar tsani (pulang 13 Dzulhijjah).", Arabic: "", Transliteration: "", TranslationText: "", Notes: "Urutan: dari jumrah yang paling kecil (Ula) → tengah (Wustha) → besar (Aqabah/Kubra). Lontar setelah zawal (tergelincir matahari) adalah waktu yang sah.", IsWajib: true},
		{Type: model.ManasikTypeHaji, StepOrder: 10, Title: "Thawaf Wada' (Thawaf Perpisahan)", Description: "Sebelum meninggalkan Makkah, wajib melakukan Thawaf Wada' (thawaf perpisahan) sebanyak 7 putaran. Ini adalah thawaf terakhir sebelum pulang ke tanah air. Setelah thawaf wada', tidak boleh tinggal lama di Makkah — segera berangkat.", Arabic: "", Transliteration: "", TranslationText: "", Notes: "Wanita haid/nifas dimaafkan dari thawaf wada' (HR. Bukhari No. 1755). Haji selesai.", IsWajib: true},
	}

	allSteps := append(umrahSteps, hajiSteps...)
	for i := range allSteps {
		db.Clauses(clause.OnConflict{
			Columns:   []clause.Column{{Name: "type"}, {Name: "step_order"}},
			DoUpdates: clause.AssignmentColumns([]string{"title", "description", "arabic", "transliteration", "translation", "notes", "is_wajib"}),
		}).Create(&allSteps[i])
	}
}

func seedIslamicTerms(db *gorm.DB) {
	terms := []model.IslamicTerm{
		{Term: "Aqidah", Category: model.TermCategoryAqidah, Definition: "Keyakinan atau kepercayaan yang tertanam kuat dalam hati, berkaitan dengan hal-hal yang wajib diimani: Allah, malaikat, kitab, rasul, hari akhir, dan qadha-qadar.", Example: "Aqidah Ahlus Sunnah wal Jamaah menjadi landasan pemikiran Islam mayoritas.", Source: "Al-Aqidah Ath-Thahawiyyah", Origin: "Bahasa Arab: عقيدة (aqada = mengikat/menguatkan)"},
		{Term: "Tauhid", Category: model.TermCategoryAqidah, Definition: "Mengesakan Allah dalam tiga aspek: Rububiyyah (Allah satu-satunya Pencipta dan Pengatur), Uluhiyyah (Allah satu-satunya yang berhak disembah), dan Asma' wa Shifat (Allah memiliki nama dan sifat yang unik).", Example: "Kalimat 'Laa ilaaha illallah' adalah inti dari Tauhid Uluhiyyah.", Source: "Kitab At-Tauhid, Muhammad bin Abdul Wahhab", Origin: "Bahasa Arab: وحّد (wahhada = mengesakan)"},
		{Term: "Shirk", Category: model.TermCategoryAqidah, Definition: "Menyekutukan Allah dengan sesuatu yang lain dalam ibadah, ketaatan, atau sifat. Shirk akbar (besar) membatalkan keislaman, shirk ashghar (kecil) seperti riya' tidak membatalkan keislaman tapi tetap dosa besar.", Example: "Berdoa kepada selain Allah adalah shirk akbar.", Source: "QS. An-Nisa: 48", Origin: "Bahasa Arab: شرك (syarika = bersekutu)"},
		{Term: "Bid'ah", Category: model.TermCategoryAqidah, Definition: "Mengada-adakan hal baru dalam agama yang tidak ada dasarnya dari Al-Quran dan Sunnah. Para ulama berbeda pendapat: sebagian menganggap semua bid'ah sesat, sebagian membaginya menjadi bid'ah hasanah (baik) dan bid'ah dhalalah (sesat).", Example: "Nabi ﷺ bersabda: 'Setiap bid'ah adalah sesat' (HR. Muslim).", Source: "HR. Muslim No. 867", Origin: "Bahasa Arab: بدع (bada'a = menciptakan sesuatu yang baru)"},
		{Term: "Fiqh", Category: model.TermCategoryFiqh, Definition: "Ilmu tentang hukum-hukum syariat Islam yang bersifat praktis ('amaliyyah) yang diambil dari dalil-dalil terperinci (Al-Quran, Hadith, Ijma', Qiyas).", Example: "Fiqh mengatur masalah sholat, puasa, zakat, nikah, muamalah, dan pidana.", Source: "Al-Iqna', Al-Hajjawi", Origin: "Bahasa Arab: فقه (faqiha = memahami)"},
		{Term: "Halal", Category: model.TermCategoryFiqh, Definition: "Sesuatu yang diperbolehkan oleh syariat Islam untuk dilakukan, dikonsumsi, atau digunakan.", Example: "Daging sapi yang disembelih dengan cara syar'i adalah halal.", Source: "QS. Al-Baqarah: 168", Origin: "Bahasa Arab: حلّ (halla = dilepaskan/dibolehkan)"},
		{Term: "Haram", Category: model.TermCategoryFiqh, Definition: "Sesuatu yang dilarang secara mutlak oleh syariat Islam. Melakukannya mendapat dosa, meninggalkannya mendapat pahala.", Example: "Riba, zina, membunuh tanpa hak, dan minum khamr adalah haram.", Source: "QS. Al-Baqarah: 275", Origin: "Bahasa Arab: حرم (haruma = dilarang/diharamkan)"},
		{Term: "Makruh", Category: model.TermCategoryFiqh, Definition: "Sesuatu yang lebih baik ditinggalkan tapi tidak berdosa jika dilakukan. Lawannya adalah mustahab/sunnah.", Example: "Makan dengan tangan kiri, berwudhu sambil berbicara sia-sia adalah makruh.", Source: "Raudhah Ath-Thalibin, An-Nawawi", Origin: "Bahasa Arab: كره (kariha = tidak menyukai)"},
		{Term: "Sunnah / Mustahab", Category: model.TermCategoryFiqh, Definition: "Amalan yang dianjurkan oleh syariat; mendapat pahala jika dilakukan, tidak berdosa jika ditinggalkan. Dalam terminologi hadith, sunnah merujuk pada semua perkataan, perbuatan, dan ketetapan Nabi ﷺ.", Example: "Sholat rawatib, membaca basmalah sebelum makan, dan bersiwak adalah sunnah.", Source: "Al-Majmu', An-Nawawi", Origin: "Bahasa Arab: سنّ (sanna = menjalankan kebiasaan)"},
		{Term: "Wajib / Fardhu", Category: model.TermCategoryFiqh, Definition: "Amalan yang diwajibkan oleh syariat; mendapat pahala jika dilakukan, berdosa jika ditinggalkan. Fardhu dibagi: fardhu ain (kewajiban setiap individu) dan fardhu kifayah (kewajiban kolektif, gugur jika sudah ada yang melakukan).", Example: "Sholat 5 waktu adalah fardhu ain. Sholat jenazah adalah fardhu kifayah.", Source: "Al-Ghayah wat Taqrib, Abu Syuja'", Origin: "Bahasa Arab: وجب (wajaba = menjadi wajib)"},
		{Term: "Mubah", Category: model.TermCategoryFiqh, Definition: "Sesuatu yang boleh dilakukan atau ditinggalkan tanpa pahala atau dosa.", Example: "Makan nasi, tidur siang, berjalan-jalan adalah mubah.", Source: "Al-Asybah wan Nadhair, As-Suyuthi", Origin: "Bahasa Arab: أباح (abaaha = membolehkan)"},
		{Term: "Ijma'", Category: model.TermCategoryFiqh, Definition: "Kesepakatan para mujtahid (ulama yang memenuhi syarat ijtihad) dari kalangan umat Islam setelah wafatnya Nabi ﷺ atas suatu hukum syariat. Ijma' adalah sumber hukum Islam ketiga setelah Al-Quran dan Hadith.", Example: "Ijma' ulama tentang wajibnya sholat 5 waktu adalah dalil yang kuat.", Source: "Al-Ihkam fi Ushul Al-Ahkam, Al-Amidi", Origin: "Bahasa Arab: أجمع (ajma'a = bersepakat)"},
		{Term: "Qiyas", Category: model.TermCategoryFiqh, Definition: "Menyamakan hukum suatu perkara yang tidak ada nashnya (belum ada dalil eksplisit) dengan hukum perkara yang sudah ada nashnya karena memiliki 'illat (alasan hukum) yang sama.", Example: "Haramnya khamr (minuman memabukkan) diqiyaskan kepada semua minuman yang memabukkan karena 'illat-nya sama: memabukkan.", Source: "Ar-Risalah, Imam Syafi'i", Origin: "Bahasa Arab: قاس (qaasa = mengukur/menyamakan)"},
		{Term: "Ijtihad", Category: model.TermCategoryFiqh, Definition: "Pengerahan segenap kemampuan seorang mujtahid untuk mengistinbath (menyimpulkan) hukum syariat dari dalil-dalil terperinci. Syarat mujtahid: hafal Al-Quran, menguasai hadith, menguasai bahasa Arab, ilmu ushul fiqh, dll.", Example: "Penetapan awal Ramadan melalui hisab atau ru'yat adalah hasil ijtihad ulama.", Source: "Al-Mustashfa, Al-Ghazali", Origin: "Bahasa Arab: جهد (jahada = bersungguh-sungguh)"},
		{Term: "Tawassul", Category: model.TermCategoryAqidah, Definition: "Bertawassul (menjadikan perantara) dalam berdoa. Tawassul yang disepakati boleh: dengan nama/sifat Allah, dengan amal sholih sendiri, dengan doa orang sholih yang masih hidup. Tawassul yang diperselisihkan: dengan kedudukan orang sholih yang sudah wafat.", Example: "Tawassul dengan amal sholih dilakukan para sahabat di Gua Tsur (HR. Bukhari No. 2272).", Source: "At-Tawassul, Ibnu Taimiyah", Origin: "Bahasa Arab: وسّل (wassala = menjadikan perantara)"},
		{Term: "Tawakkal", Category: model.TermCategoryTasawuf, Definition: "Menyerahkan segala urusan kepada Allah setelah berusaha secara maksimal. Bukan berarti pasif tanpa usaha — Nabi ﷺ memerintahkan untuk 'mengikat unta dulu baru bertawakkal'.", Example: "Tawakkal yang benar: berobat dulu, baru pasrahkan hasilnya kepada Allah.", Source: "HR. Tirmidzi No. 2517", Origin: "Bahasa Arab: وكّل (wakkala = mewakilkan/menyerahkan)"},
		{Term: "Zuhud", Category: model.TermCategoryTasawuf, Definition: "Tidak mencintai dunia secara berlebihan; meninggalkan hal-hal yang tidak bermanfaat untuk akhirat. Bukan berarti miskin atau tidak bekerja — para sahabat kaya seperti Utsman dan Abdurrahman bin Auf adalah ahli zuhud.", Example: "Nabi ﷺ bersabda: 'Zuhud di dunia bukan berarti mengharamkan yang halal atau membuang harta, tapi (zuhud adalah) bahwa yang ada di tangan Allah lebih engkau percaya daripada yang ada di tanganmu.' (HR. Tirmidzi)", Source: "HR. Tirmidzi No. 2340", Origin: "Bahasa Arab: زهد (zahida = membenci/tidak menginginkan)"},
		{Term: "Wara'", Category: model.TermCategoryTasawuf, Definition: "Berhati-hati dalam menghindari hal-hal yang meragukan (syubhat) karena khawatir jatuh ke yang haram. Tingkatan di atas zuhud.", Example: "Imam Ahmad menolak minum air dari sumber yang tidak jelas kehalalannya saat melewati suatu kota.", Source: "Ihya Ulumuddin, Al-Ghazali", Origin: "Bahasa Arab: ورع (wari'a = berhati-hati)"},
		{Term: "Taubat", Category: model.TermCategoryTasawuf, Definition: "Kembali kepada Allah dari dosa dengan tiga syarat: menyesali dosa yang telah dilakukan, meninggalkan dosa tersebut saat ini, dan bertekad tidak mengulangi. Jika dosa berkaitan dengan hak manusia, harus mengembalikan hak tersebut.", Example: "Taubat nasuha adalah taubat yang sungguh-sungguh dan tidak berulang (QS. At-Tahrim: 8).", Source: "QS. At-Tahrim: 8; HR. Tirmidzi No. 3539", Origin: "Bahasa Arab: تاب (taaba = kembali)"},
		{Term: "Tazkiyatun Nafs", Category: model.TermCategoryTasawuf, Definition: "Penyucian jiwa dari akhlak tercela (riya, hasad, sombong, dll) dan menghiasi diri dengan akhlak terpuji (ikhlas, sabar, syukur, dll). Merupakan tujuan akhir dari ibadah.", Example: "Puasa mengajarkan tazkiyatun nafs karena memaksa jiwa menahan nafsu.", Source: "QS. Asy-Syams: 9; Ihya Ulumuddin, Al-Ghazali", Origin: "Bahasa Arab: زكّى (zakka = menyucikan)"},
		{Term: "Muhkam", Category: model.TermCategoryUlumulQuran, Definition: "Ayat Al-Quran yang jelas maknanya dan tidak mengandung kemungkinan makna lain. Lawannya adalah mutasyabih (samar).", Example: "Ayat-ayat tentang hukum ibadah umumnya muhkam. QS. Ali Imran: 7 menyebutkan bahwa ayat muhkam adalah 'ummul kitab' (induk kitab).", Source: "Al-Burhan fi Ulum Al-Quran, Az-Zarkasyi", Origin: "Bahasa Arab: أحكم (ahkama = menguatkan/memperjelas)"},
		{Term: "Nasikh-Mansukh", Category: model.TermCategoryUlumulQuran, Definition: "Nasikh: hukum yang menghapus hukum sebelumnya. Mansukh: hukum yang dihapus. Penghapusan hukum ini terjadi dalam Al-Quran maupun Sunnah, tapi hanya berlaku antar ayat/hadith yang sezaman dengan masa Nabi ﷺ.", Example: "Perintah puasa Asyura dimansukh (dihapus kewajibannya) oleh kewajiban puasa Ramadan.", Source: "Al-Ittiqan fi Ulum Al-Quran, As-Suyuthi", Origin: "Bahasa Arab: نسخ (nasakha = menghapus/menyalin)"},
		{Term: "Asbabun Nuzul", Category: model.TermCategoryUlumulQuran, Definition: "Sebab-sebab turunnya ayat Al-Quran. Mengetahui asbabun nuzul membantu memahami konteks dan maksud ayat dengan tepat.", Example: "Asbabun nuzul QS. Al-Lahab (111) adalah peristiwa ketika Abu Lahab menolak seruan Nabi ﷺ di bukit Shafa.", Source: "Asbabun Nuzul, Al-Wahidi; Lubab An-Nuqul, As-Suyuthi", Origin: "Bahasa Arab: نزل (nazala = turun)"},
		{Term: "Mutawatir", Category: model.TermCategoryHadith, Definition: "Hadith yang diriwayatkan oleh sejumlah besar perawi yang mustahil bersepakat untuk berbohong, dari awal sanad hingga akhir. Mutawatir memberikan keyakinan mutlak (qath'i).", Example: "Hadith tentang jumlah rakaat sholat 5 waktu adalah mutawatir.", Source: "Nukhbah Al-Fikr, Ibnu Hajar Al-Asqalani", Origin: "Bahasa Arab: توتّر (tawatara = datang berurutan/bertubi-tubi)"},
		{Term: "Ahad", Category: model.TermCategoryHadith, Definition: "Hadith yang tidak mencapai derajat mutawatir — diriwayatkan oleh satu atau beberapa orang. Dibagi menjadi masyhur (3+ perawi), aziz (2 perawi), dan gharib (1 perawi). Hadith ahad yang shahih tetap wajib diamalkan.", Example: "Sebagian besar hadith dalam kitab Bukhari dan Muslim adalah hadith ahad shahih.", Source: "Nukhbah Al-Fikr, Ibnu Hajar Al-Asqalani", Origin: "Bahasa Arab: أحد (ahad = satu/seorang)"},
		{Term: "Shahih", Category: model.TermCategoryHadith, Definition: "Hadith yang memenuhi 5 syarat: sanadnya bersambung, semua perawi adil (muslim, berakal, tidak fasiq), semua perawi dhabit (kuat hafalannya), tidak ada syadz (bertentangan dengan yang lebih kuat), tidak ada 'illat (cacat tersembunyi).", Example: "Shahih Bukhari dan Shahih Muslim adalah koleksi hadith paling shahih.", Source: "Muqaddimah Ibnu Ash-Shalah", Origin: "Bahasa Arab: صحّ (shahha = sehat/benar)"},
		{Term: "Dha'if", Category: model.TermCategoryHadith, Definition: "Hadith yang tidak memenuhi syarat shahih atau hasan karena ada kelemahan pada sanad atau matan. Hadith dha'if tidak boleh dijadikan dalil hukum, namun sebagian ulama membolehkannya untuk fadhail amal (keutamaan amalan) dengan syarat ketat.", Example: "Hadith 'Cintai tanah airmu bagian dari iman' adalah hadith yang sangat dha'if.", Source: "Taqrib At-Tahdzib, Ibnu Hajar", Origin: "Bahasa Arab: ضعف (dha'ufa = lemah)"},
		{Term: "Isnad / Sanad", Category: model.TermCategoryHadith, Definition: "Rantai perawi yang menghubungkan teks hadith (matan) kepada Nabi ﷺ. Ilmu isnad adalah keistimewaan Islam yang tidak dimiliki agama lain.", Example: "Contoh sanad: 'Dari Al-Bukhari, dari Yahya bin Bukair, dari Al-Laits, dari 'Uqail, dari Ibnu Syihab, dari Salim, dari Abdullah bin Umar...'", Source: "Al-Kifayah fi Ilm Ar-Riwayah, Al-Khatib Al-Baghdadi", Origin: "Bahasa Arab: سند (sanada = bersandar)"},
	}

	for i := range terms {
		db.Clauses(clause.OnConflict{
			Columns:   []clause.Column{{Name: "term"}},
			DoUpdates: clause.AssignmentColumns([]string{"category", "definition", "example", "source", "origin"}),
		}).Create(&terms[i])
	}
}
